import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,d as e}from"./app-0a44add1.js";const t="/img/study/html/reflow.jpg",i={},l=e('<h2 id="重绘与回流" tabindex="-1"><a class="header-anchor" href="#重绘与回流" aria-hidden="true">#</a> 重绘与回流</h2><ul><li>重绘：当我们对 DOM 的修改导致了样式的变化、却并未影响其几何属性（比如修改了颜色或背景色）时，浏览器不需重新计算元素的几何属性、直接为该元素绘制新的样式（跳过了上图所示的回流环节）。</li><li>重排：当我们对 DOM 的修改引发了 DOM 几何尺寸的变化（比如修改元素的宽、高或隐藏元素等）时，浏览器需要重新计算元素的几何属性（其他元素的几何属性和位置也会因此受到影响），然后再将计算的结果绘制出来。这个过程就是重排</li></ul><p>我们知道，当网页生成的时候，至少会渲染一次。在用户访问的过程中，还会不断重新渲染。重新渲染会重复重排+重绘或者只有重绘。<br> 重排必定会发生重绘，重绘不一定会引发重排。重绘和重排会在我们设置节点样式时频繁出现，同时也会很大程度上影响性能。重排所需的成本比重绘高的多，改变父节点里的子节点很可能会导致父节点的一系列回流。</p><h2 id="常见引起重排属性和方法" tabindex="-1"><a class="header-anchor" href="#常见引起重排属性和方法" aria-hidden="true">#</a> 常见引起重排属性和方法</h2><p>任何会改变元素几何信息(元素的位置和尺寸大小)的操作，都会触发重排，</p><ul><li>添加或者删除可见的DOM元素；</li><li>元素尺寸改变——边距、填充、边框、宽度和高度</li><li>内容变化，比如用户在input框中输入文字</li><li>浏览器窗口尺寸改变——resize事件发生时</li><li>计算 offsetWidth 和 offsetHeight 属性</li><li>设置 style 属性的值</li></ul><h2 id="常见引起重绘属性和方法" tabindex="-1"><a class="header-anchor" href="#常见引起重绘属性和方法" aria-hidden="true">#</a> 常见引起重绘属性和方法</h2><figure><img src="'+t+`" alt=" " tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="如何减少重排、重绘" tabindex="-1"><a class="header-anchor" href="#如何减少重排、重绘" aria-hidden="true">#</a> 如何减少重排、重绘</h2><ul><li>使用 transform 替代 top</li><li>使用 visibility 替换 display: none ，因为前者只会引起重绘，后者会引发回流（改变了布局）</li><li>不要把节点的属性值放在一个循环里当成循环里的变量。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">for</span><span class="token punctuation">(</span><span class="token keyword">let</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">1000</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 获取 offsetTop 会导致回流，因为需要去获取正确的值</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>document<span class="token punctuation">.</span><span class="token function">querySelector</span><span class="token punctuation">(</span><span class="token string">&#39;.test&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>style<span class="token punctuation">.</span>offsetTop<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不要使用 table 布局，可能很小的一个小改动会造成整个 table 的重新布局</li><li>动画实现的速度的选择，动画速度越快，回流次数越多，也可以选择使用 requestAnimationFrame</li><li>CSS 选择符从右往左匹配查找，避免节点层级过多</li><li>将频繁重绘或者回流的节点设置为图层，图层能够阻止该节点的渲染行为影响别的节点。比如对于 video 标签来说，浏览器会自动将该节点变为图层。</li></ul>`,12),o=[l];function p(c,r){return a(),s("div",null,o)}const h=n(i,[["render",p],["__file","重绘与重排.html.vue"]]);export{h as default};
